class Solution:
    def shortestBridge(self, grid):
        from collections import deque
        n = len(grid)
        dirs = [(0,1),(0,-1),(1,0),(-1,0)]
        visited = [[False]*n for _ in range(n)]
        queue = deque()
        found = False
        for r in range(n):
            if found:
                break
            for c in range(n):
                if grid[r][c] == 1:
                    stack = [(r, c)]
                    visited[r][c] = True
                    while stack:
                        x, y = stack.pop()
                        queue.append((x, y, 0))
                        for dx, dy in dirs:
                            nx, ny = x+dx, y+dy
                            if 0 <= nx < n and 0 <= ny < n and not visited[nx][ny] and grid[nx][ny] == 1:
                                visited[nx][ny] = True
                                stack.append((nx, ny))
                    found = True
                    break
        while queue:
            x, y, dist = queue.popleft()
            for dx, dy in dirs:
                nx, ny = x+dx, y+dy
                if 0 <= nx < n and 0 <= ny < n and not visited[nx][ny]:
                    if grid[nx][ny] == 1:
                        return dist
                    visited[nx][ny] = True
                    queue.append((nx, ny, dist+1))
        return -1

