class Solution:
    def shortestBridge(self, grid):
        from collections import deque
        n = len(grid)
        dirs = [(0,1),(0,-1),(1,0),(-1,0)]
        visited = [[False]*n for _ in range(n)]
        bfs_queue = deque()
        # find first island via DFS
        def dfs(r, c):
            if r < 0 or r >= n or c < 0 or c >= n or visited[r][c] or grid[r][c] == 0:
                return
            visited[r][c] = True
            bfs_queue.append((r, c, 0))
            for dr, dc in dirs:
                dfs(r+dr, c+dc)
        import sys
        sys.setrecursionlimit(20000)
        found = False
        for r in range(n):
            if found: break
            for c in range(n):
                if grid[r][c] == 1:
                    dfs(r, c)
                    found = True
                    break
        while bfs_queue:
            x, y, dist = bfs_queue.popleft()
            for dx, dy in dirs:
                nx, ny = x+dx, y+dy
                if 0 <= nx < n and 0 <= ny < n and not visited[nx][ny]:
                    if grid[nx][ny] == 1:
                        return dist
                    visited[nx][ny] = True
                    bfs_queue.append((nx, ny, dist+1))
        return -1

