var shortestBridge = function(grid) {
    const n = grid.length;
    const dirs = [[0,1],[0,-1],[1,0],[-1,0]];
    const visited = Array.from({length:n}, () => new Array(n).fill(false));
    const bfsQueue = [];
    let head = 0;
    // iterative DFS to mark first island
    let found = false;
    for (let r = 0; r < n && !found; r++) {
        for (let c = 0; c < n && !found; c++) {
            if (grid[r][c] === 1) {
                const stack = [[r, c]];
                visited[r][c] = true;
                while (stack.length) {
                    const [x, y] = stack.pop();
                    bfsQueue.push([x, y, 0]);
                    for (const [dx, dy] of dirs) {
                        const nx = x+dx, ny = y+dy;
                        if (nx>=0&&nx<n&&ny>=0&&ny<n&&!visited[nx][ny]&&grid[nx][ny]===1) {
                            visited[nx][ny] = true;
                            stack.push([nx, ny]);
                        }
                    }
                }
                found = true;
            }
        }
    }
    while (head < bfsQueue.length) {
        const [x, y, dist] = bfsQueue[head++];
        for (const [dx, dy] of dirs) {
            const nx = x+dx, ny = y+dy;
            if (nx>=0&&nx<n&&ny>=0&&ny<n&&!visited[nx][ny]) {
                if (grid[nx][ny] === 1) return dist;
                visited[nx][ny] = true;
                bfsQueue.push([nx, ny, dist+1]);
            }
        }
    }
    return -1;
};
